const raw = items[0]?.json || {};
const payload = raw.payload && typeof raw.payload === 'object' && !Array.isArray(raw.payload) ? raw.payload : raw;
const messageId = payload.message_id || payload.messageId || raw.message_id || raw.messageId;
const threadId = payload.thread_id || payload.threadId || raw.thread_id || raw.threadId || messageId;
const fromEmail = payload.from_email || payload.from || raw.from_email || raw.from;
const subject = payload.subject || raw.subject || '(no subject)';
const body = payload.body || payload.bodyText || raw.body || raw.bodyText || payload.snippet || raw.snippet || payload.bodyHtml || raw.bodyHtml || '';
if (!messageId) throw new Error('Missing message_id / messageId');
if (!fromEmail) throw new Error('Missing from_email / from');
if (!body) throw new Error('Missing body / bodyText / bodyHtml');
return [{
  json: {
    meta: {
      workflow_name: 'Gmail_Support_Inbox',
      timestamp: new Date().toISOString(),
      trigger_source: raw.trigger_source || 'support_inbox_webhook',
      risk_level: raw.risk_level || 'medium'
    },
    context: {
      canonical_links: [
        '[[08-Runbooks/Support/Gmail-Support-Inbox-Workflow|Gmail Support Inbox Workflow]]',
        '[[08-Runbooks/System/Escalation-Matrix|Escalation Matrix]]'
      ],
      constraints: [
        'No unsupported promises',
        'No refunds, pricing exceptions, or compliance commitments via automation'
      ]
    },
    payload: {
      message_id: String(messageId),
      thread_id: String(threadId),
      from_email: String(fromEmail),
      subject: String(subject),
      body: String(body),
      body_html: String(payload.body_html || payload.bodyHtml || raw.body_html || raw.bodyHtml || ''),
      received_at: String(payload.received_at || payload.receivedAt || raw.received_at || raw.receivedAt || new Date().toISOString()),
      account: String(payload.account || raw.account || payload.mailbox || raw.mailbox || ''),
      mailbox: String(payload.mailbox || raw.mailbox || payload.account || raw.account || '')
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'status', 'message_id', 'thread_id', 'from_email', 'subject', 'reply_subject', 'label', 'route_lane', 'reply_draft', 'safe_to_send', 'escalate_to', 'technical_target', 'faq_candidate', 'reason'];
for (const key of required) {
  if (!(key in item)) throw new Error(`Missing required key: ${key}`);
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) throw new Error(`Invalid status: ${item.status}`);
const allowedLabels = new Set(['support', 'lead', 'onboarding', 'technical', 'billing', 'compliance_risk']);
if (!allowedLabels.has(item.label)) throw new Error(`Invalid label: ${item.label}`);
const allowedLanes = new Set(['support_reply', 'technical_escalation', 'billing_escalation', 'compliance_escalation']);
if (!allowedLanes.has(item.route_lane)) throw new Error(`Invalid route_lane: ${item.route_lane}`);
const allowedEscalation = new Set(['none', 'AI-1', 'AI-2', 'AI-3', 'AI-5', 'AI-6', 'AI-7', 'AI-8', 'AI-9', 'AI-10', 'AI-11', 'Owner']);
if (!allowedEscalation.has(item.escalate_to)) throw new Error(`Invalid escalate_to: ${item.escalate_to}`);
const allowedTechnical = new Set(['none', 'AI-1', 'AI-2']);
if (!allowedTechnical.has(item.technical_target)) throw new Error(`Invalid technical_target: ${item.technical_target}`);
item.gmail_reply_request = item.safe_to_send && item.escalate_to === 'none'
  ? {
      account: item.account || item.mailbox,
      to: item.from_email,
      subject: item.reply_subject,
      body_html: String(item.reply_draft || '').replace(/\n/g, '<br>'),
      threadId: item.thread_id,
      messageId: item.message_id
    }
  : null;
item.execution_action = item.safe_to_send && item.escalate_to === 'none'
  ? 'send_or_manual_review'
  : 'create_escalation_note';
return [{ json: item }];
